using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

/// <summary>
/// A static class providing a method to download content from multiple URIs concurrently.
/// </summary>
public static class Downloader
{
    /// <summary>
    /// Fetches content from multiple URIs concurrently using a provided fetch delegate.
    /// </summary>
    /// <param name="uris">An enumerable collection of URIs to fetch.</param>
    /// <param name="fetch">A delegate that takes a URI and a CancellationToken and returns a Task representing the asynchronous fetch operation for that URI's content.</param>
    /// <param name="cancellationToken">A CancellationToken to observe while waiting for the tasks to complete.</param>
    /// <returns>
    /// A task that represents the asynchronous operation. The task result contains an array of strings
    /// with the fetched content, ordered corresponding to the input <paramref name="uris"/>.
    /// </returns>
    /// <remarks>
    /// This method starts all fetch operations concurrently. If the <paramref name="cancellationToken"/> is canceled,
    /// it is expected that the individual fetch operations will honor it and throw an <see cref="OperationCanceledException"/>.
    /// This method will then propagate the exception, and the returned task will be faulted.
    /// </remarks>
    /// <exception cref="ArgumentNullException">Thrown if <paramref name="uris"/> or <paramref name="fetch"/> is null.</exception>
    /// <exception cref="OperationCanceledException">Thrown if the operation is canceled via the <paramref name="cancellationToken"/>.</exception>
    public static async Task<string[]> DownloadAllAsync(
        IEnumerable<Uri> uris,
        Func<Uri, CancellationToken, Task<string>> fetch,
        CancellationToken cancellationToken)
    {
        ArgumentNullException.ThrowIfNull(uris);
        ArgumentNullException.ThrowIfNull(fetch);

        // Create and start a task for each URI.
        // .ToArray() materializes the collection, ensuring all fetch operations are initiated
        // before we start awaiting any of them, thus maximizing concurrency.
        var downloadTasks = uris.Select(uri => fetch(uri, cancellationToken)).ToArray();

        // Await all tasks to complete.
        // Task.WhenAll returns an array of results in the same order as the input tasks.
        // If any of the tasks are canceled, Task.WhenAll will propagate the
        // OperationCanceledException, and the 'await' will re-throw it.
        return await Task.WhenAll(downloadTasks);
    }
}

using System.Threading.Channels;
using System.Threading.Tasks;

/// <summary>
/// Provides a static method to demonstrate a producer-consumer pipeline using System.Threading.Channels.
/// </summary>
public static class Pipeline
{
    /// <summary>
    /// Produces integers from 0 to count-1 into a bounded channel,
    /// consumes them concurrently, and returns their sum.
    /// </summary>
    /// <param name="count">The number of integers to produce. Must be non-negative.</param>
    /// <returns>A task that represents the asynchronous operation, containing the sum of the integers as a long.</returns>
    public static Task<long> ProduceConsumeSumAsync(int count)
    {
        if (count <= 0)
        {
            return Task.FromResult(0L);
        }

        // 1. Create a bounded channel. A capacity of 100 is chosen as a reasonable
        //    default to demonstrate back-pressure without being too small.
        //    The 'Wait' mode ensures the producer blocks when the channel is full.
        var channel = Channel.CreateBounded<int>(new BoundedChannelOptions(100)
        {
            FullMode = BoundedChannelFullMode.Wait,
            SingleReader = true, // Optimization since we have one consumer
            SingleWriter = true  // Optimization since we have one producer
        });

        // 2. Start a background task for the producer.
        Task producer = Task.Run(async () =>
        {
            try
            {
                for (int i = 0; i < count; i++)
                {
                    // Write to the channel, asynchronously waiting if the channel is full.
                    await channel.Writer.WriteAsync(i);
                }
            }
            finally
            {
                // 3. Signal that production is complete. This is crucial for the
                //    consumer's reading loop to terminate gracefully.
                channel.Writer.Complete();
            }
        });

        // 4. Create and return the consumer task.
        //    The caller of ProduceConsumeSumAsync will await this task.
        return ConsumeAndSumAsync(channel.Reader);
    }

    /// <summary>
    /// Consumes integers from the channel reader and calculates their sum.
    /// </summary>
    private static async Task<long> ConsumeAndSumAsync(ChannelReader<int> reader)
    {
        long sum = 0;

        // The await foreach loop efficiently reads from the channel.
        // It asynchronously waits for items to become available and
        // completes automatically when the channel is marked as complete
        // by the producer and all items have been read.
        await foreach (var item in reader.ReadAllAsync())
        {
            sum += item;
        }

        return sum;
    }
}

using System.Threading;

/// <summary>
/// A sealed class representing a thread-safe counter.
/// </summary>
public sealed class Counter
{
    private long _value = 0;

    /// <summary>
    /// Atomically increments the counter's value by one.
    /// This operation is safe to call concurrently from multiple threads.
    /// </summary>
    public void Increment()
    {
        Interlocked.Increment(ref _value);
    }

    /// <summary>
    /// Gets the current value of the counter.
    /// The read operation is performed atomically to ensure the latest value is returned.
    /// </summary>
    public long Value
    {
        get => Volatile.Read(ref _value);
    }
}

using System;

/// <summary>
/// Provides a read-only view of a value of a specific type.
/// </summary>
/// <typeparam name="T">The type of the value. This type parameter is covariant.</typeparam>
public interface IReadOnlyBox<out T>
{
    /// <summary>
    /// Gets the value contained in the box.
    /// </summary>
    T Value { get; }
}

/// <summary>
/// Represents a simple container that holds a value of a specific type.
/// </summary>
/// <typeparam name="T">The type of the value to be stored.</typeparam>
public sealed class Box<T> : IReadOnlyBox<T>
{
    /// <summary>
    /// Initializes a new instance of the <see cref="Box{T}"/> class with the specified value.
    /// </summary>
    /// <param name="value">The value to be stored in the box.</param>
    public Box(T value)
    {
        Value = value;
    }

    /// <summary>
    /// Gets the value contained in the box.
    /// </summary>
    public T Value { get; }
}

