/// <summary>
/// Provides aggregation methods using generic math.
/// </summary>
public static class Aggregate
{
    /// <summary>
    /// Computes the sum of a sequence of numeric values.
    /// </summary>
    /// <typeparam name="T">The type of the values, which must implement <see cref="INumber{T}"/>.</typeparam>
    /// <param name="values">A sequence of values to calculate the sum of.</param>
    /// <returns>The sum of the values in the sequence. Returns <c>T.Zero</c> if the sequence is empty.</returns>
    public static T Sum<T>(IEnumerable<T> values) where T : INumber<T>
    {
        T sum = T.Zero;
        foreach (T value in values)
        {
            sum += value;
        }
        return sum;
    }
}

using System;

public abstract record Shape;

public record Circle(double Radius) : Shape;

public record Rectangle(double Width, double Height) : Shape;

public record Triangle(double Base, double Height) : Shape;

public static class Geometry
{
    public static double Area(Shape shape)
    {
        return shape switch
        {
            Circle c => Math.PI * c.Radius * c.Radius,
            Rectangle r => r.Width * r.Height,
            Triangle t => 0.5 * t.Base * t.Height,
            _ => throw new ArgumentException("Unsupported shape type provided.", nameof(shape))
        };
    }
}

