using System.Collections.Generic;

/// <summary>
/// A sealed class for associating string values with string keys.
/// </summary>
sealed class Lookup
{
    private readonly Dictionary<string, string> _storage = new();

    /// <summary>
    /// Associates a value with a key. If the key already exists, 
    /// the previous value is overwritten.
    /// </summary>
    /// <param name="key">The key to associate the value with.</param>
    /// <param name="value">The value to store.</param>
    public void Add(string key, string value)
    {
        _storage[key] = value;
    }

    /// <summary>
    /// Attempts to get the value associated with the specified key.
    /// </summary>
    /// <param name="key">The key of the value to get.</param>
    /// <param name="value">
    /// When this method returns, contains the value associated with the specified key, 
    /// if the key is found; otherwise, null.
    /// </param>
    /// <returns>
    /// true if the key was found; otherwise, false.
    /// </returns>
    public bool TryGet(string key, out string? value)
    {
        return _storage.TryGetValue(key, out value);
    }
}

