using System;

/// <summary>
/// Provides a static method to resolve a configuration value from multiple sources.
/// </summary>
public static class Config
{
    /// <summary>
    /// Returns the first non-null, non-empty string from a set of prioritized values.
    /// </summary>
    /// <param name="primary">The primary value to check. Can be null or empty.</param>
    /// <param name="fallback">The fallback value, used if the primary is null or empty. Can be null or empty.</param>
    /// <param name="default">The default value, used if both primary and fallback are null or empty. This value is guaranteed to be non-null.</param>
    /// <returns>The resolved string value, which will never be null.</returns>
    public static string Resolve(string? primary, string? fallback, string @default)
    {
        if (!string.IsNullOrEmpty(primary))
        {
            return primary;
        }

        if (!string.IsNullOrEmpty(fallback))
        {
            return fallback;
        }

        return @default;
    }
}

