/// <summary>
/// A modern C# rewrite of the original class, preserving its exact behavior.
/// This version utilizes several modern C# features:
/// - Expression-bodied member for the method.
/// - Switch expression to handle the different states of 'count'.
/// - Type pattern (`int c`) to safely unwrap the non-null integer value.
/// - Null-coalescing operator (`??`) to provide a default value for 'label'.
/// - String interpolation to construct the final output string concisely.
/// </summary>
public static class Inventory
{
    public static string Describe(int? count, string? label) =>
        $"{(count switch
        {
            null => "unknown",
            0 => "no",
            int c => c.ToString()
        })} {label ?? "items"}";
}

using System;

/// <summary>
/// A static class for scanning text represented by spans without allocations.
/// </summary>
public static class TextScan
{
    /// <summary>
    /// Counts the number of whitespace-separated words in the provided text.
    /// </summary>
    /// <param name="text">The text to scan. This can be a slice of a string or other character buffer.</param>
    /// <returns>The total number of words found.</returns>
    /// <remarks>
    /// This method is allocation-free. It considers any sequence of one or more
    //  whitespace characters as a single separator. Leading and trailing
    /// whitespace are ignored and do not result in empty words. An empty or
    /// whitespace-only input will correctly return 0.
    /// </remarks>
    public static int CountWords(ReadOnlySpan<char> text)
    {
        int wordCount = 0;
        bool inWord = false;

        // Iterate through each character in the span.
        foreach (char c in text)
        {
            if (char.IsWhiteSpace(c))
            {
                // We have encountered whitespace. If we were previously inside a word,
                // this marks the end of that word.
                inWord = false;
            }
            else
            {
                // We have encountered a non-whitespace character.
                // If we were not previously inside a word, this marks the beginning
                // of a new word. We increment the count and update our state.
                if (!inWord)
                {
                    wordCount++;
                    inWord = true;
                }
            }
        }

        return wordCount;
    }
}

using System;
using System.Globalization;

/// <summary>
/// A static class for parsing data from spans without allocations.
/// </summary>
public static class SpanParser
{
    /// <summary>
    /// Parses comma-separated base-10 integers from a read-only character span and returns their sum.
    /// </summary>
    /// <param name="csv">A span containing comma-separated integers. For example, "1,2,-3, 42".</param>
    /// <returns>The sum of the parsed integers. Returns 0 for an empty span.</returns>
    /// <remarks>
    /// This method is allocation-free. It processes the span directly without creating substrings or other heap-allocated objects.
    /// It handles positive and negative integers, and correctly ignores whitespace around numbers and empty entries (e.g., "1,,2").
    /// </remarks>
    public static int SumCsvInts(ReadOnlySpan<char> csv)
    {
        int totalSum = 0;

        // Process the span segment by segment until it has been fully consumed.
        while (!csv.IsEmpty)
        {
            // Find the index of the next comma separator.
            int commaIndex = csv.IndexOf(',');

            ReadOnlySpan<char> numberSpan;

            if (commaIndex == -1)
            {
                // No comma found, so this is the last (or only) number in the span.
                numberSpan = csv;
                // Consume the rest of the span to terminate the loop.
                csv = ReadOnlySpan<char>.Empty;
            }
            else
            {
                // A comma was found. The number is the slice before the comma.
                numberSpan = csv.Slice(0, commaIndex);
                // Advance the span to start after the comma for the next iteration.
                csv = csv.Slice(commaIndex + 1);
            }

            // Trim leading and trailing whitespace from the number segment.
            // This is an allocation-free operation on a span.
            numberSpan = numberSpan.Trim();

            // If the segment is not empty after trimming, parse it and add to the sum.
            if (!numberSpan.IsEmpty)
            {
                // int.Parse(ReadOnlySpan<char>) is used to avoid allocations.
                totalSum += int.Parse(numberSpan, NumberStyles.Integer, CultureInfo.InvariantCulture);
            }
        }

        return totalSum;
    }
}
